module top_module(clk,reset,key,IRQ,Key_RD);input clk;
    input reset;

    input [7:0] key;


    output reg IRQ;
    output [31:0] Key_RD;


    reg [7:0] obf_data;

    assign Key_RD={24'b0,obf_data};

    always @(posedge clk)
        begin
            if(reset)
                begin
                    obf_data<=0;
                    IRQ<=0;
                end 
            else if(obf_data!=~key)
                begin
                    obf_data<=~key;
                    IRQ<=1;
                end
            else
                begin
                    obf_data<=obf_data;
                    IRQ<=0;
                end
        end

endmodule
